import ast

def evaluate_expression(expr: str) -> str:
    try:
        tree = ast.parse(expr, mode='eval')
    except Exception:
        return ''

    allowed_nodes = (ast.Expression, ast.BinOp, ast.UnaryOp, ast.Num, ast.Constant)
    allowed_ops = (ast.Add, ast.Sub, ast.Mult, ast.Div, ast.FloorDiv, ast.Mod, ast.Pow, ast.UAdd, ast.USub)

    for node in ast.walk(tree):
        if not isinstance(node, allowed_nodes):
            return ''
        if isinstance(node, ast.BinOp):
            if not isinstance(node.op, allowed_ops):
                return ''
        if isinstance(node, ast.UnaryOp):
            if not isinstance(node.op, allowed_ops):
                return ''
        if isinstance(node, ast.Constant):
            if not isinstance(node.value, (int, float)):
                return ''

    try:
        code = compile(tree, '<string>', 'eval')
        result = eval(code, {"__builtins__": None}, {})
        if not isinstance(result, (int, float, complex)):
            return ''
        return str(result)
    except Exception:
        return ''

