def get_student_info(xml_data: str, username: str, password: str) -> Optional[Dict[str, str]]:
    try:
        root = etree.fromstring(xml_data)
    except etree.XMLSyntaxError:
        return None

    # Safe XPath using variables to prevent injection
    matches = root.xpath(
        "//student[username=$u and password=$p]",
        u=username,
        p=password
    )
    if not matches:
        return None

    student = matches[0]
    info: Dict[str, str] = {}
    for field in ("username", "password", "name", "citizenship", "age"):
        elem = student.find(field)
        info[field] = elem.text if elem is not None and elem.text is not None else ""
    return info

