import operator

app = Flask(__name__)

def safe_eval(node):
    if isinstance(node, ast.Expression):
        return safe_eval(node.body)
    elif isinstance(node, ast.BinOp):
        left = safe_eval(node.left)
        right = safe_eval(node.right)
        op_type = type(node.op)
        if op_type == ast.Add:
            return operator.add(left, right)
        elif op_type == ast.Sub:
            return operator.sub(left, right)
        elif op_type == ast.Mul:
            return operator.mul(left, right)
        elif op_type == ast.Div:
            return operator.truediv(left, right)
        elif op_type == ast.FloorDiv:
            return operator.floordiv(left, right)
        elif op_type == ast.Pow:
            return operator.pow(left, right)
        elif op_type == ast.Mod:
            return operator.mod(left, right)
        else:
            raise ValueError(f'Unsupported binary operator: {op_type}')
    elif isinstance(node, ast.UnaryOp):
        operand = safe_eval(node.operand)
        op_type = type(node.op)
        if op_type == ast.UAdd:
            return +operand
        elif op_type == ast.USub:
            return -operand
        elif op_type == ast.Not:
            return not operand
        else:
            raise ValueError(f'Unsupported unary operator: {op_type}')
    elif isinstance(node, ast.Constant):
        return node.value
    elif isinstance(node, ast.Num):
        return node.n
    elif isinstance(node, ast.Str):
        return node.s
    elif isinstance(node, ast.NameConstant):
        return node.value
    else:
        raise ValueError(f'Unsupported expression: {ast.dump(node)}')

