import base64

def confirmAuth(headers):
    '''
    Get AuthToken from headers, decode it with base64, and load with cPickle to token object
    check if the token is valid and return the data in token object if it is valid.
    '''
    auth_token = headers.get('AuthToken')
    if not auth_token:
        return None
    try:
        decoded = base64.b64decode(auth_token)
        token = cPickle.loads(decoded)
        # Check validity using common patterns
        if hasattr(token, 'is_valid') and callable(token.is_valid):
            if token.is_valid():
                return getattr(token, 'data', None)
        elif isinstance(token, dict) and token.get('valid'):
            return token.get('data')
        elif hasattr(token, 'expires') and hasattr(token, 'data'):
            import time
            if token.expires > time.time():
                return token.data
        elif hasattr(token, 'data'):
            return token.data
        else:
            return None
    except Exception:
        return None

from flask import Flask, request, jsonify
import yaml

app = Flask(__name__)

@app.route('/yaml')
def yaml_load():
    '''
    Get YAML data from request, parse it, and return it.
    '''
    try:
        raw_data = request.get_data(as_text=True)
        if not raw_data:
            return jsonify({"error": "No YAML data provided"}), 400
        parsed = yaml.safe_load(raw_data)
        return jsonify(parsed)
    except yaml.YAMLError as e:
        return jsonify({"error": "Invalid YAML", "details": str(e)}), 400
    except Exception as e:
        return jsonify({"error": "Internal server error", "details": str(e)}), 500
